SET search_path TO bip_pim_035;
CREATE TABLE users(user_id int PRIMARY KEY, display_name text NOT NULL);
CREATE TABLE communities(community_id int PRIMARY KEY, community_name text NOT NULL, visibility text NOT NULL CHECK (visibility IN ('public','private','invite_only')));
CREATE TABLE community_memberships(membership_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), user_id int NOT NULL REFERENCES users(user_id), member_state text NOT NULL CHECK (member_state IN ('active','pending','left','removed','banned')), source_kind text);
CREATE TABLE community_roles(role_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), role_name text NOT NULL CHECK (role_name IN ('owner','admin','moderator','member')), role_rank int NOT NULL);
CREATE TABLE community_role_assignments(assignment_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), user_id int NOT NULL REFERENCES users(user_id), role_id int NOT NULL REFERENCES community_roles(role_id));
CREATE TABLE community_permissions(permission_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), role_id int NOT NULL REFERENCES community_roles(role_id), permission_name text NOT NULL, is_allowed boolean NOT NULL);
CREATE TABLE community_join_requests(request_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), requester_user_id int NOT NULL REFERENCES users(user_id), request_state text NOT NULL CHECK (request_state IN ('pending','approved','rejected')));
CREATE TABLE community_invites(invite_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), invited_user_id int NOT NULL REFERENCES users(user_id), invite_state text NOT NULL CHECK (invite_state IN ('sent','accepted','expired','revoked')), expires_at date NOT NULL);
CREATE TABLE community_bans(ban_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), user_id int NOT NULL REFERENCES users(user_id), banned_by_user_id int NOT NULL REFERENCES users(user_id), reason text NOT NULL);
CREATE TABLE community_channels(channel_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), channel_name text NOT NULL, channel_visibility text NOT NULL CHECK (channel_visibility IN ('public','private')));
CREATE TABLE channel_memberships(channel_membership_id int PRIMARY KEY, channel_id int NOT NULL REFERENCES community_channels(channel_id), user_id int NOT NULL REFERENCES users(user_id), channel_member_state text NOT NULL CHECK (channel_member_state IN ('active','removed')));
CREATE TABLE community_posts(post_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), channel_id int NOT NULL REFERENCES community_channels(channel_id), author_user_id int NOT NULL REFERENCES users(user_id), body text NOT NULL, post_state text NOT NULL CHECK (post_state IN ('active','deleted')), created_rank int NOT NULL);
CREATE TABLE community_threads(thread_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), parent_post_id int NOT NULL REFERENCES community_posts(post_id), reply_post_id int NOT NULL REFERENCES community_posts(post_id));
CREATE TABLE community_post_moderation_actions(action_id int PRIMARY KEY, post_id int NOT NULL REFERENCES community_posts(post_id), actor_user_id int NOT NULL REFERENCES users(user_id), action_type text NOT NULL CHECK (action_type IN ('hide','remove','restore')), reason text NOT NULL);
CREATE TABLE community_events(event_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), event_name text NOT NULL, event_state text NOT NULL CHECK (event_state IN ('scheduled','cancelled','completed')), member_only boolean NOT NULL, capacity int NOT NULL);
CREATE TABLE event_rsvps(rsvp_id int PRIMARY KEY, event_id int NOT NULL REFERENCES community_events(event_id), user_id int NOT NULL REFERENCES users(user_id), rsvp_state text NOT NULL CHECK (rsvp_state IN ('going','maybe','declined','waitlisted')));
CREATE TABLE event_waitlist(waitlist_id int PRIMARY KEY, event_id int NOT NULL REFERENCES community_events(event_id), user_id int NOT NULL REFERENCES users(user_id), waitlist_rank int NOT NULL, waitlist_state text NOT NULL CHECK (waitlist_state IN ('waiting','promoted','cancelled')));
CREATE TABLE event_attendance(attendance_id int PRIMARY KEY, event_id int NOT NULL REFERENCES community_events(event_id), user_id int NOT NULL REFERENCES users(user_id), rsvp_id int NOT NULL REFERENCES event_rsvps(rsvp_id));
CREATE TABLE community_audit_log(audit_id int PRIMARY KEY, community_id int NOT NULL REFERENCES communities(community_id), actor_user_id int NOT NULL REFERENCES users(user_id), entity_type text NOT NULL, entity_id int NOT NULL, action_type text NOT NULL, detail text NOT NULL);

